async (page) => {
  const skillData = await page.evaluate(() => {
    const player = window.game?.player;
    const str = player?.skills?.[6];
    const health = player?.skills?.[3];

    // Check all properties of the Strength skill
    const strProps = {};
    if (str) {
      Object.keys(str).forEach(k => { strProps[k] = str[k]; });
    }

    return {
      strength_raw: strProps,
      attack_style: player?.attackStyle,
      weapon: player?.equipment?.weapon?.key || player?.weapon || 'none',
      allSkillsXP: Object.entries(player?.skills || {}).map(([k,v]) => `${k}:${v?.name}=${v?.experience}`)
    };
  });
  return skillData;
}

